"use client";
import React from "react";

export default function CenterPanel() {
  // Données mockées basées sur ta maquette
  const stats = [
    {
      label: "ELIMINATIONS",
      leftVal: "42",
      leftPct: 80,
      rightVal: "28",
      rightPct: 40,
      leftWins: true,
    },
    {
      label: "ASSISTS",
      leftVal: "12",
      leftPct: 20,
      rightVal: "34",
      rightPct: 80,
      leftWins: false,
    },
    {
      label: "DEATHS",
      leftVal: "5",
      leftPct: 15,
      rightVal: "8",
      rightPct: 25,
      leftWins: true,
    },
    {
      label: "DAMAGE DEALT",
      leftVal: "14.2k",
      leftPct: 90,
      rightVal: "6.8k",
      rightPct: 45,
      leftWins: true,
    },
    {
      label: "HEALING DONE",
      leftVal: "0",
      leftPct: 0,
      rightVal: "11.5k",
      rightPct: 100,
      leftWins: false,
    },
    {
      label: "ULTIMATE USES",
      leftVal: "6",
      leftPct: 60,
      rightVal: "4",
      rightPct: 40,
      leftWins: true,
    },
    {
      label: "CRITICAL HITS",
      leftVal: "54",
      leftPct: 85,
      rightVal: "12",
      rightPct: 20,
      leftWins: true,
    },
    {
      label: "SOLO KILLS",
      leftVal: "18",
      leftPct: 75,
      rightVal: "2",
      rightPct: 10,
      leftWins: true,
    },
    {
      label: "OBJECTIVE TIME",
      leftVal: "1:24",
      leftPct: 35,
      rightVal: "2:45",
      rightPct: 85,
      leftWins: false,
    },
    {
      label: "BARRIER DAMAGE",
      leftVal: "2.1k",
      leftPct: 40,
      rightVal: "0.5k",
      rightPct: 10,
      leftWins: true,
    },
  ];

  return (
    <div
      className="bg-white d-flex flex-column h-100 px-4 py-3"
      style={{ flexGrow: 1, borderTopLeftRadius: "20px", minWidth: "500px" }}
    >
      {/* En-tête : GameMode et Update Stats */}
      <div className="d-flex justify-content-between align-items-center mb-4">
        <div className="text-secondary fw-bold" style={{ fontSize: "0.9rem" }}>
          GameMode <span style={{ fontSize: "0.7rem" }}>▼</span>
        </div>
        <button
          className="btn fw-bold bg-white"
          style={{
            border: "2px solid #f09c13",
            color: "#333",
            padding: "5px 20px",
            borderRadius: "5px",
          }}
        >
          UPDATE STATS
        </button>
        <div style={{ width: "80px" }}></div>{" "}
        {/* Espace pour équilibrer le flex */}
      </div>

      {/* Logo VS Central */}
      <div
        className="d-flex justify-content-center align-items-center mb-5"
        style={{ height: "60px" }}
      >
        <div
          className="fw-bold fst-italic fs-1"
          style={{ letterSpacing: "-2px" }}
        >
          <span className="text-dark">V</span>
          <span className="text-secondary">S</span>
        </div>
      </div>

      {/* Barre Console | PC & Titre MATCH STATISTIQUES */}
      <div className="d-flex justify-content-between align-items-center mb-4 border-bottom pb-2">
        {/* Switch Joueur 1 */}
        <div className="d-flex fw-bold" style={{ fontSize: "0.85rem" }}>
          <span
            className="px-2 py-1 bg-warning text-dark rounded"
            style={{ backgroundColor: "#f09c13 !important" }}
          >
            Console
          </span>
          <span className="px-2 py-1 text-secondary border-start ms-1">PC</span>
        </div>

        {/* Titre central */}
        <div
          className="fw-bold text-uppercase text-secondary"
          style={{ fontSize: "1.2rem", color: "#cdd3d8 !important" }}
        >
          MATCH STATISTIQUES
        </div>

        {/* Switch Joueur 2 */}
        <div className="d-flex fw-bold" style={{ fontSize: "0.85rem" }}>
          <span
            className="px-2 py-1 bg-warning text-dark rounded"
            style={{ backgroundColor: "#f09c13 !important" }}
          >
            Console
          </span>
          <span className="px-2 py-1 text-secondary border-start ms-1">PC</span>
        </div>
      </div>

      {/* Liste des statistiques */}
      <div className="d-flex flex-column" style={{ gap: "15px" }}>
        {stats.map((stat, index) => (
          <div
            key={index}
            className="d-flex align-items-center justify-content-between"
          >
            {/* Valeur Gauche */}
            <div
              className={`fw-bold text-end ${stat.leftWins ? "text-warning" : "text-secondary"}`}
              style={{
                width: "50px",
                color: stat.leftWins ? "#f09c13 !important" : "",
              }}
            >
              {stat.leftVal}
            </div>

            {/* Barre Gauche (se remplit de droite à gauche) */}
            <div
              className="flex-grow-1 ms-3 me-4 bg-light rounded-pill d-flex justify-content-end"
              style={{ height: "8px" }}
            >
              <div
                className="rounded-pill"
                style={{
                  width: `${stat.leftPct}%`,
                  backgroundColor: stat.leftWins ? "#f09c13" : "#cdd3d8",
                }}
              ></div>
            </div>

            {/* Nom de la stat */}
            <div
              className="fw-bold text-secondary text-center text-uppercase"
              style={{ width: "160px", fontSize: "0.85rem" }}
            >
              {stat.label}
            </div>

            {/* Barre Droite (se remplit de gauche à droite) */}
            <div
              className="flex-grow-1 ms-4 me-3 bg-light rounded-pill d-flex justify-content-start"
              style={{ height: "8px" }}
            >
              <div
                className="rounded-pill"
                style={{
                  width: `${stat.rightPct}%`,
                  backgroundColor: !stat.leftWins ? "#f09c13" : "#cdd3d8",
                }}
              ></div>
            </div>

            {/* Valeur Droite */}
            <div
              className={`fw-bold text-start ${!stat.leftWins ? "text-warning" : "text-secondary"}`}
              style={{
                width: "50px",
                color: !stat.leftWins ? "#f09c13 !important" : "",
              }}
            >
              {stat.rightVal}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
